if (!s) return str_dup("");
size_t cap = strlen(s) + 1;
char *out = (char *)malloc(cap);
if (!out) return NULL;
size_t oi = 0;
for (size_t i = 0; s[i]; ) {
    if (s[i] == '\033' && s[i + 1] == '[') {
        i += 2;
        while (s[i] && s[i] != 'm') i++;
        if (s[i] == 'm') i++;
        continue;
    }
    out[oi++] = s[i++];
}
out[oi] = '\0';
return out;
